CREATE OR REPLACE FUNCTION pgv_ut.test_call_ref()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Without route prefix (app mode): no validation, simple path
  PERFORM set_config('pgv.route_prefix', '', true);

  RETURN NEXT is(pgv.call_ref('get_index'), '/',
    'get_index without prefix → /');

  RETURN NEXT is(pgv.call_ref('get_drawings'), '/drawings',
    'get_drawings without prefix → /drawings');

  RETURN NEXT is(pgv.call_ref('get_drawing', '{"id": "42"}'::jsonb), '/drawing?id=42',
    'get_drawing with param → /drawing?id=42');

  RETURN NEXT is(pgv.call_ref('post_save', '{"id": "1", "name": "test"}'::jsonb), '/save?id=1&name=test',
    'post_save with multiple params → query string');

  -- With route prefix (dev mode): validates against pg_proc
  PERFORM set_config('pgv.route_prefix', '/pgv_qa', true);

  RETURN NEXT is(pgv.call_ref('get_index'), '/pgv_qa/',
    'get_index with prefix → /pgv_qa/');

  RETURN NEXT is(pgv.call_ref('get_atoms'), '/pgv_qa/atoms',
    'get_atoms (exists in pgv_qa) → /pgv_qa/atoms');

  -- Dead link detection
  RETURN NEXT throws_ok(
    $$SELECT pgv.call_ref('get_does_not_exist')$$,
    'P0001',
    'pgv.call_ref: function pgv_qa.get_does_not_exist not found',
    'dead link raises exception'
  );
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_call_ref() IS 'Tests for pgv.call_ref: path generation, prefix handling, dead link detection';

CREATE OR REPLACE FUNCTION pgv_ut.test_card()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v text;
BEGIN
  -- Basic card
  v := pgv.card('Title', '<p>Body</p>');
  RETURN NEXT ok(v LIKE '%<article>%', 'has article tag');
  RETURN NEXT ok(v LIKE '%<header>Title</header>%', 'has header');
  RETURN NEXT ok(v LIKE '%<p>Body</p>%', 'has body');
  RETURN NEXT ok(v NOT LIKE '%<footer>%', 'no footer when NULL');

  -- Card with footer
  v := pgv.card('T', 'B', 'F');
  RETURN NEXT ok(v LIKE '%<footer>F</footer>%', 'has footer');

  -- Card without title
  v := pgv.card(NULL, 'B');
  RETURN NEXT ok(v NOT LIKE '%<header>%', 'no header when NULL');

  -- Markdown mode
  v := pgv.card('MD Card', '| A | B |', p_md := true);
  RETURN NEXT ok(v LIKE '%<md>%', 'md mode wraps in md tag');
  RETURN NEXT ok(v LIKE '%| A | B |%', 'md content preserved');
  RETURN NEXT ok(v LIKE '%</md>%', 'md closing tag');

  -- Default (no markdown)
  v := pgv.card('Plain', '| A | B |');
  RETURN NEXT ok(v NOT LIKE '%<md>%', 'default mode no md tag');

  RETURN;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_card() IS 'Test pgv.card() — article card with optional markdown body';

CREATE OR REPLACE FUNCTION pgv_ut.test_check_crud()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v text;
BEGIN
  v := pgv.check_crud('docs');

  -- Header
  RETURN NEXT ok(v LIKE 'check_crud: docs%', 'header present');

  -- Entities with CRUD detected
  RETURN NEXT ok(v LIKE '%charter — create read list%delete%', 'charter: CRUD detected');
  RETURN NEXT ok(v LIKE '%document — create read list%delete%', 'document: CRUD detected');
  RETURN NEXT ok(v LIKE '%library — create read list%delete%', 'library: CRUD detected');

  -- Naming warning
  RETURN NEXT ok(v LIKE '%⚠ naming: page_remove%', 'naming: page_remove detected');

  -- Entities without CRUD get warning
  RETURN NEXT ok(v LIKE '%⚠ page — no CRUD%', 'page: no CRUD warning');
  RETURN NEXT ok(v LIKE '%⚠ session — no CRUD%', 'session: no CRUD warning');

  -- Summary
  RETURN NEXT ok(v LIKE '%warning(s)%', 'summary has warnings');

  -- Schema with no issues (pgv_qa has product table but no CRUD)
  v := pgv.check_crud('pgv_qa');
  RETURN NEXT ok(v LIKE '%check_crud: pgv_qa%', 'pgv_qa: runs without error');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_check_crud() IS 'Tests pgv.check_crud() — CRUD convention audit';

