CREATE OR REPLACE FUNCTION pgv_ut.test_form_dialog()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v text;
BEGIN
  -- Basic output
  v := pgv.form_dialog('dlg1', 'Titre', '<input name="x">', 'post_foo');
  RETURN NEXT ok(v LIKE '%data-form-dialog="dlg1"%', 'trigger button has data-form-dialog');
  RETURN NEXT ok(v LIKE '%<dialog id="dlg1"%', 'dialog has correct id');
  RETURN NEXT ok(v LIKE '%class="pgv-form-dialog"%', 'dialog has pgv-form-dialog class');
  RETURN NEXT ok(v LIKE '%data-rpc="post_foo"%', 'form has data-rpc');
  RETURN NEXT ok(v LIKE '%data-dialog-form%', 'form has data-dialog-form marker');
  RETURN NEXT ok(v LIKE '%pgv-form-dialog-article%', 'article class present');
  RETURN NEXT ok(v LIKE '%pgv-form-dialog-header%', 'header class present');
  RETURN NEXT ok(v LIKE '%pgv-form-dialog-close%', 'close button class present');
  RETURN NEXT ok(v LIKE '%pgv-form-dialog-body%', 'body class present');
  RETURN NEXT ok(v LIKE '%pgv-form-dialog-footer%', 'footer class present');
  RETURN NEXT ok(v LIKE '%<input name="x">%', 'body content preserved');

  -- Title escaping
  v := pgv.form_dialog('d2', 'A&B', '', 'rpc');
  RETURN NEXT ok(v LIKE '%A&amp;B%', 'title is escaped');

  -- Custom label
  v := pgv.form_dialog('d3', 'Title', '', 'rpc', 'Click me');
  RETURN NEXT ok(v LIKE '%>Click me</button>%', 'custom label on trigger');

  -- Variant outline
  v := pgv.form_dialog('d4', 'T', '', 'rpc', NULL, 'outline');
  RETURN NEXT ok(v LIKE '%class="outline"%', 'outline variant applied');

  -- Variant secondary
  v := pgv.form_dialog('d5', 'T', '', 'rpc', NULL, 'secondary');
  RETURN NEXT ok(v LIKE '%class="secondary"%', 'secondary variant applied');

  -- data-src for lazy load
  v := pgv.form_dialog('d6', 'T', '', 'rpc', NULL, NULL, '/edit_form?id=1');
  RETURN NEXT ok(v LIKE '%data-src="/edit_form?id=1"%', 'data-src attribute present');

  -- No data-src when NULL
  v := pgv.form_dialog('d7', 'T', '', 'rpc');
  RETURN NEXT ok(v NOT LIKE '%data-src%', 'no data-src when p_src is NULL');

  -- i18n: cancel and send buttons
  v := pgv.form_dialog('d8', 'T', '', 'rpc');
  RETURN NEXT ok(v LIKE '%' || pgv.t('cancel') || '%', 'cancel button uses i18n');
  RETURN NEXT ok(v LIKE '%' || pgv.t('send') || '%', 'send button uses i18n');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_form_dialog() IS 'Unit tests for pgv.form_dialog() primitive';

CREATE OR REPLACE FUNCTION pgv_ut.test_fts()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  -- Stemming: "poutre" matches "poutres", "Poutre"
  v_result := pgv_qa.data_products('{"q":"poutre"}'::jsonb);
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') > 0, 'poutre matches Poutre (case-insensitive)');
  RETURN NEXT ok(v_result->'rows'->0->>1 LIKE '%outre%', 'poutre result contains poutre in name');

  -- Accent: "chene" matches "chêne"
  v_result := pgv_qa.data_products('{"q":"chene"}'::jsonb);
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 2, 'chene matches chêne (accent-insensitive)');

  -- Multi-word: "coffrage beton" matches planche de coffrage
  v_result := pgv_qa.data_products('{"q":"coffrage beton"}'::jsonb);
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') > 0, 'coffrage beton matches multi-word');

  -- No match
  v_result := pgv_qa.data_products('{"q":"xyz123"}'::jsonb);
  RETURN NEXT is(jsonb_array_length(v_result->'rows'), 0, 'xyz123 no match → rows empty');
  RETURN NEXT is((v_result->>'has_more')::bool, false, 'xyz123 no match → has_more false');

  -- Cursor pagination: offset 0, size 5
  v_result := pgv_qa.data_products('{"_offset":0,"_size":5}'::jsonb);
  RETURN NEXT is(jsonb_array_length(v_result->'rows'), 5, 'cursor offset=0 returns 5 rows');
  RETURN NEXT is((v_result->>'has_more')::bool, true, 'cursor offset=0 has_more = true');

  -- Cursor pagination: past end
  v_result := pgv_qa.data_products('{"_offset":9999,"_size":5}'::jsonb);
  RETURN NEXT is(jsonb_array_length(v_result->'rows'), 0, 'cursor past end returns 0 rows');
  RETURN NEXT is((v_result->>'has_more')::bool, false, 'cursor past end has_more = false');

  -- Filter: category = bois
  v_result := pgv_qa.data_products('{"p_category":"bois"}'::jsonb);
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 5, 'category filter bois returns >= 5');

  -- Filter + FTS combined
  v_result := pgv_qa.data_products('{"p_category":"quincaillerie","q":"vis"}'::jsonb);
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'category + FTS combined works');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_fts() IS 'Tests FTS pgv_search: stemming, accents, multi-words, pagination, empty results';

CREATE OR REPLACE FUNCTION pgv_ut.test_href()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(pgv.href('https://example.com') = 'https://example.com', 'href passes https');
  RETURN NEXT ok(pgv.href('http://example.com') = 'http://example.com', 'href passes http');
  RETURN NEXT ok(pgv.href('//example.com') = '//example.com', 'href passes protocol-relative');
  RETURN NEXT ok(pgv.href('mailto:a@b.com') = 'mailto:a@b.com', 'href passes mailto');
  RETURN NEXT ok(pgv.href('tel:+33123') = 'tel:+33123', 'href passes tel');

  RETURN NEXT throws_ok(
    $$SELECT pgv.href('/atoms')$$,
    'P0001',
    'pgv.href() is for external URLs only — use pgv.call_ref() for internal links. Got: /atoms',
    'href RAISEs on internal path /atoms'
  );
  RETURN NEXT throws_ok(
    $$SELECT pgv.href('/')$$,
    'P0001',
    'pgv.href() is for external URLs only — use pgv.call_ref() for internal links. Got: /',
    'href RAISEs on internal path /'
  );
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_href() IS 'Unit tests for pgv.href: whitelist protocols, RAISEs on internal paths';

CREATE OR REPLACE FUNCTION pgv_ut.test_html_audit()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
BEGIN
  -- 1. Returns text
  RETURN NEXT ok(pg_typeof(pgv.html_audit('pgv'))::text = 'text', 'returns text');

  -- 2. Always returns a report (even for unknown schema — shows "clean")
  v_result := pgv.html_audit('nonexistent_schema_xyz');
  RETURN NEXT ok(v_result LIKE '%HTML audit%', 'report header for unknown schema');
  RETURN NEXT ok(v_result LIKE '%clean%', 'clean badge for unknown schema');

  -- 3. pgv schema runs without error
  v_result := pgv.html_audit('pgv');
  RETURN NEXT ok(v_result LIKE '%HTML audit%', 'report header for pgv');

  -- 4. Result contains findings for schemas with raw HTML
  v_result := pgv.html_audit('crm');
  IF v_result LIKE '%raw HTML%' THEN
    RETURN NEXT ok(v_result LIKE '%<md>%', 'markdown table present when findings');
  ELSE
    RETURN NEXT ok(v_result LIKE '%clean%', 'crm clean — shows clean badge');
  END IF;

  -- 5. pgv_ut schema shows clean (test functions, no get_/post_)
  v_result := pgv.html_audit('pgv_ut');
  RETURN NEXT ok(v_result LIKE '%clean%', 'test schema shows clean');

  RETURN;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_html_audit() IS 'Test pgv.html_audit() — detects raw HTML that should use pgv.* primitives';

CREATE OR REPLACE FUNCTION pgv_ut.test_i18n()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Seed translations
  PERFORM pgv.i18n_seed();

  -- Default lang (fr) resolves known key
  PERFORM set_config('pgv.lang', 'fr', true);
  RETURN NEXT ok(pgv.t('pgv.error') = 'Erreur', 't() returns French value for known key');

  -- Missing key returns the key itself
  RETURN NEXT ok(pgv.t('nonexistent.key') = 'nonexistent.key', 't() returns key when not found');

  -- Unknown lang falls back to French
  PERFORM set_config('pgv.lang', 'de', true);
  RETURN NEXT ok(pgv.t('pgv.error') = 'Erreur', 't() falls back to fr for unknown lang');

  -- Empty lang setting defaults to fr
  PERFORM set_config('pgv.lang', '', true);
  RETURN NEXT ok(pgv.t('pgv.error') = 'Erreur', 't() defaults to fr when lang is empty');

  -- Unset lang defaults to fr
  PERFORM set_config('pgv.lang', '', true);
  RETURN NEXT ok(pgv.t('pgv.issue_reported') = 'Signalement envoyé, merci !', 't() resolves accented value');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_i18n() IS 'Unit tests for pgv.t() i18n lookup: default lang, fallback, missing key';

CREATE OR REPLACE FUNCTION pgv_ut.test_lazy()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- Basic lazy
  v_html := pgv.lazy('load_data');
  RETURN NEXT ok(v_html LIKE '%pgv-lazy%', 'lazy has pgv-lazy class');
  RETURN NEXT ok(v_html LIKE '%data-lazy="load_data"%', 'lazy has data-lazy attr');
  RETURN NEXT ok(v_html LIKE '%aria-busy="true"%', 'lazy has loading indicator');

  -- With params
  v_html := pgv.lazy('load_detail', '{"id": 42}'::jsonb);
  RETURN NEXT ok(v_html LIKE '%data-params%', 'lazy with params has data-params');
  RETURN NEXT ok(v_html LIKE '%"id": 42%', 'lazy params contain value');

  -- No params = no data-params attr
  v_html := pgv.lazy('simple_load', '{}'::jsonb);
  RETURN NEXT ok(v_html NOT LIKE '%data-params%', 'lazy with empty params omits data-params');

  -- XSS in rpc name
  v_html := pgv.lazy('"><script>');
  RETURN NEXT ok(v_html NOT LIKE '%<script>%', 'lazy escapes rpc name');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_lazy() IS 'Unit tests for pgv.lazy: data-lazy, params, XSS';

CREATE OR REPLACE FUNCTION pgv_ut.test_link_button()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v text;
BEGIN
  -- 1. Basic link button (primary)
  v := pgv.link_button('/clients', 'Clients');
  RETURN NEXT ok(v LIKE '%<a href%', 'has anchor tag');
  RETURN NEXT ok(v LIKE '%role="button"%', 'has role button');
  RETURN NEXT ok(v LIKE '%pgv-link-button%', 'has pgv-link-button class');
  RETURN NEXT ok(v LIKE '%>Clients</a>%', 'has label');

  -- 2. Outline variant
  v := pgv.link_button('/new', 'New', 'outline');
  RETURN NEXT ok(v LIKE '%outline%', 'outline class present');

  -- 3. Secondary variant
  v := pgv.link_button('/back', 'Back', 'secondary');
  RETURN NEXT ok(v LIKE '%secondary%', 'secondary class present');

  -- 4. Contrast variant
  v := pgv.link_button('/x', 'X', 'contrast');
  RETURN NEXT ok(v LIKE '%contrast%', 'contrast class present');

  -- 5. XSS safety
  v := pgv.link_button('/x" onclick="alert(1)', 'Test');
  RETURN NEXT ok(v LIKE '%&quot;%', 'href is escaped');

  -- 6. Label escaping
  v := pgv.link_button('/x', '<script>alert(1)</script>');
  RETURN NEXT ok(v LIKE '%&lt;script&gt;%', 'label is escaped');

  RETURN;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_link_button() IS 'Test pgv.link_button() — navigation link styled as button';

CREATE OR REPLACE FUNCTION pgv_ut.test_md_table()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_ok boolean;
BEGIN
  -- Basic table
  v_html := pgv.md_table(ARRAY['A', 'B'], ARRAY['1', '2', '3', '4']);
  RETURN NEXT ok(v_html LIKE '%<md>%', 'md_table wraps in md tag');
  RETURN NEXT ok(v_html LIKE '%| A | B |%', 'md_table has headers');
  RETURN NEXT ok(v_html LIKE '%| 1 | 2 |%', 'md_table has first row');
  RETURN NEXT ok(v_html LIKE '%| 3 | 4 |%', 'md_table has second row');

  -- Empty rows
  v_html := pgv.md_table(ARRAY['X', 'Y'], NULL);
  RETURN NEXT ok(v_html LIKE '%| X | Y |%', 'md_table with null rows has headers');
  RETURN NEXT ok(v_html LIKE '%| --- |%', 'md_table with null rows has separator');

  -- Modulo assertion
  BEGIN
    v_html := pgv.md_table(ARRAY['A', 'B', 'C'], ARRAY['1', '2']);
    v_ok := false;
  EXCEPTION WHEN raise_exception THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'md_table raises on non-multiple row count');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_md_table() IS 'Unit tests for pgv.md_table: basic, empty, modulo assertion';

CREATE OR REPLACE FUNCTION pgv_ut.test_nav()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  PERFORM set_config('pgv.route_prefix', '/test', true);
  v_html := pgv.nav('Test', '[
    {"href": "/test/", "label": "Home"},
    {"href": "https://example.com", "label": "External"}
  ]'::jsonb, '/test/');

  -- Theme toggle
  RETURN NEXT ok(v_html LIKE '%data-toggle-theme%', 'nav has theme toggle');
  RETURN NEXT ok(v_html LIKE '%pgv-theme-toggle%', 'theme toggle has CSS class');

  -- External link
  RETURN NEXT ok(v_html LIKE '%target="_blank"%', 'external link has target=_blank');
  RETURN NEXT ok(v_html LIKE '%rel="noopener"%', 'external link has rel=noopener');
  RETURN NEXT ok(v_html LIKE '%href="https://example.com"%', 'external href preserved');

  -- Current page
  RETURN NEXT ok(v_html LIKE '%aria-current="page"%', 'current page has aria-current');

  -- No htmx
  RETURN NEXT ok(v_html NOT LIKE '%hx-%', 'nav has no hx-* attributes');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_nav() IS 'Unit tests for pgv.nav: theme toggle, external links, aria-current, no htmx';

CREATE OR REPLACE FUNCTION pgv_ut.test_page()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  PERFORM set_config('pgv.route_prefix', '/test', true);
  v_html := pgv.page('Brand', 'Title', '/test/', '[{"href":"/","label":"H"}]'::jsonb, '<p>Body</p>');
  RETURN NEXT ok(v_html NOT LIKE '%style=%', 'page has no inline style');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_page() IS 'Unit test for pgv.page: no inline style';

CREATE OR REPLACE FUNCTION pgv_ut.test_radio()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := pgv.radio('freq', 'Frequence', '["jour", "semaine", "mois"]'::jsonb, 'semaine');
  RETURN NEXT ok(v_html LIKE '%type="radio"%', 'radio has type');
  RETURN NEXT ok(v_html LIKE '%name="freq"%', 'radio has name');
  RETURN NEXT ok(v_html LIKE '%checked%', 'radio has selected option');
  RETURN NEXT ok(v_html LIKE '%jour%', 'radio has first option');
  RETURN NEXT ok(v_html LIKE '%mois%', 'radio has last option');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_radio() IS 'Unit tests for pgv.radio: type, name, selected option, all options';

CREATE OR REPLACE FUNCTION pgv_ut.test_redirect()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE v text;
BEGIN
  v := pgv.redirect('/clients');
  RETURN NEXT ok(v ~ '<template data-redirect="/clients">', 'redirect path');
  RETURN NEXT ok(v ~ '></template>', 'empty body');

  v := pgv.redirect('/client?id=42');
  RETURN NEXT ok(v ~ 'data-redirect="/client\?id=42"', 'query params preserved');

  -- XSS safety
  v := pgv.redirect('/"onload="alert(1)');
  RETURN NEXT ok(v ~ '&quot;', 'quotes escaped in path');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_redirect() IS 'Tests for pgv.redirect() POST response primitive';

CREATE OR REPLACE FUNCTION pgv_ut.test_route()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_item jsonb;
  v_href text;
  v_html text;
  v_rpc text;
  v_schema text := 'pgv_qa';
  v_fname text;
BEGIN
  -- All nav pages render
  FOR v_item IN SELECT * FROM jsonb_array_elements(pgv_qa.nav_items()) LOOP
    v_href := v_item->>'href';
    IF v_href ~ '^https?://' THEN CONTINUE; END IF;
    v_html := pgv.route(v_schema, v_href, 'GET');
    RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0,
      format('route %s %s renders HTML', v_schema, v_href));
    RETURN NEXT ok(v_html LIKE '%<nav%',
      format('route %s %s has nav', v_schema, v_href));
    RETURN NEXT ok(v_html LIKE '%<main%',
      format('route %s %s has main', v_schema, v_href));
  END LOOP;

  -- Nav pages exist as functions
  FOR v_item IN SELECT * FROM jsonb_array_elements(pgv_qa.nav_items()) LOOP
    v_href := v_item->>'href';
    IF v_href ~ '^https?://' THEN CONTINUE; END IF;
    IF v_href = '/' THEN v_fname := 'get_index';
    ELSE v_fname := 'get_' || replace(replace(trim(BOTH '/' FROM v_href), '/', '_'), '-', '_');
    END IF;
    RETURN NEXT ok(
      EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
             WHERE n.nspname = v_schema AND p.proname = v_fname),
      format('nav %s -> %s.%s() exists', v_href, v_schema, v_fname));
  END LOOP;

  -- Nav hrefs prefixed with schema
  v_html := pgv.route(v_schema, '/', 'GET');
  RETURN NEXT ok(v_html LIKE '%href="/pgv_qa/"%', 'nav dashboard href prefixed');
  RETURN NEXT ok(v_html LIKE '%href="/pgv_qa/atoms"%', 'nav atoms href prefixed');
  RETURN NEXT ok(v_html LIKE '%href="/pgv_qa/forms"%', 'nav forms href prefixed');
  RETURN NEXT is(current_setting('pgv.route_prefix', true), '/pgv_qa', 'route_prefix set after route call');

  -- RPC targets exist
  FOR v_item IN SELECT * FROM jsonb_array_elements(pgv_qa.nav_items()) LOOP
    v_href := v_item->>'href';
    IF v_href ~ '^https?://' THEN CONTINUE; END IF;
    v_html := pgv.route(v_schema, v_href, 'GET');
    FOR v_rpc IN SELECT (regexp_matches(v_html, 'data-rpc="([^"]+)"', 'g'))[1] LOOP
      RETURN NEXT ok(
        EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
               WHERE n.nspname = v_schema AND p.proname = v_rpc),
        format('data-rpc="%s" on %s -> %s.%s() exists', v_rpc, v_href, v_schema, v_rpc));
    END LOOP;
  END LOOP;

  -- Typed dispatch
  EXECUTE $x$
    CREATE OR REPLACE FUNCTION pgv_qa.get_test_param(p_id integer)
    RETURNS text LANGUAGE sql AS $f$ SELECT '<p>ID=' || $1::text || '</p>'; $f$
  $x$;
  v_html := pgv.route(v_schema, '/test-param', 'GET', '{"p_id": "42"}'::jsonb);
  RETURN NEXT ok(v_html LIKE '%ID=42%', 'route dispatches get_ with scalar int param');
  RETURN NEXT ok(v_html LIKE '%<nav%', 'scalar param page has layout');

  v_html := pgv.route(v_schema, '/atoms', 'GET');
  RETURN NEXT ok(v_html LIKE '%pgv-badge%', 'route dispatches get_ with 0 args');

  EXECUTE $x$
    CREATE OR REPLACE FUNCTION pgv_qa.post_test_action()
    RETURNS text LANGUAGE sql AS $f$ SELECT '<template data-toast="success">Done</template>'; $f$
  $x$;
  v_html := pgv.route(v_schema, '/test-action', 'POST');
  RETURN NEXT ok(v_html LIKE '%data-toast%', 'POST returns toast template');
  RETURN NEXT ok(v_html NOT LIKE '%<nav%', 'POST has no layout wrapping');

  DROP FUNCTION pgv_qa.get_test_param(integer);
  DROP FUNCTION pgv_qa.post_test_action();
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route() IS 'Unit tests for pgv.route: page rendering, nav prefixing, rpc targets, typed dispatch';

CREATE OR REPLACE FUNCTION pgv_ut.test_rsql()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
BEGIN
  -- Simple equality (text)
  v_result := pgv.rsql_to_where('name==ocean', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'name = ''ocean''', 'eq text: name==ocean');

  -- Equality (numeric) — no quotes
  v_result := pgv.rsql_to_where('price==42', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'price = 42', 'eq numeric: price==42');

  -- Not equal
  v_result := pgv.rsql_to_where('status!=draft', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'status != ''draft''', 'neq: status!=draft');

  -- Greater than (numeric)
  v_result := pgv.rsql_to_where('price>100', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'price > 100', 'gt numeric: price>100');

  -- Less than equal (numeric)
  v_result := pgv.rsql_to_where('id<=5', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'id <= 5', 'lte numeric: id<=5');

  -- AND (;)
  v_result := pgv.rsql_to_where('category==bois;status==actif', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'category = ''bois'' AND status = ''actif''', 'AND: ;');

  -- OR (,)
  v_result := pgv.rsql_to_where('price>=50,category==bois', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, '(price >= 50) OR (category = ''bois'')', 'OR: ,');

  -- IN
  v_result := pgv.rsql_to_where('status=in=(draft,actif)', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'status IN (''draft'', ''actif'')', 'in: =in=()');

  -- NOT IN
  v_result := pgv.rsql_to_where('category=out=(test,tmp)', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'category NOT IN (''test'', ''tmp'')', 'out: =out=()');

  -- LIKE with wildcard
  v_result := pgv.rsql_to_where('name=like=*poutre*', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'name LIKE ''%poutre%''', 'like: *→%');

  -- ILIKE
  v_result := pgv.rsql_to_where('name=ilike=*OCEAN*', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'name ILIKE ''%OCEAN%''', 'ilike: case-insensitive');

  -- IS NULL
  v_result := pgv.rsql_to_where('description=isnull=true', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'description IS NULL', 'isnull=true → IS NULL');

  -- IS NOT NULL (via isnull=false)
  v_result := pgv.rsql_to_where('description=isnull=false', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'description IS NOT NULL', 'isnull=false → IS NOT NULL');

  -- NOTNULL
  v_result := pgv.rsql_to_where('name=notnull=true', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'name IS NOT NULL', 'notnull=true → IS NOT NULL');

  -- BETWEEN (numeric)
  v_result := pgv.rsql_to_where('price=bt=(10,50)', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'price BETWEEN 10 AND 50', 'between numeric');

  -- Combined IN + LIKE with AND
  v_result := pgv.rsql_to_where('status=in=(draft,actif);name=like=*poutre*', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'status IN (''draft'', ''actif'') AND name LIKE ''%poutre%''', 'combined in+like');

  -- Empty filter → true
  v_result := pgv.rsql_to_where('', 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'true', 'empty filter → true');

  -- NULL filter → true
  v_result := pgv.rsql_to_where(NULL, 'pgv_qa', 'product');
  RETURN NEXT is(v_result, 'true', 'null filter → true');

  -- Invalid column → RAISE
  BEGIN
    v_result := pgv.rsql_to_where('fakecol==test', 'pgv_qa', 'product');
    RETURN NEXT fail('invalid column should raise');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT ok(SQLERRM LIKE '%does not exist%', 'invalid column raises exception');
  END;

  -- Injection: quotes escaped
  v_result := pgv.rsql_to_where('name==O''Reilly', 'pgv_qa', 'product');
  RETURN NEXT ok(v_result LIKE '%O''''Reilly%', 'injection: quotes escaped');

  -- rsql_validate: valid
  RETURN NEXT is(pgv.rsql_validate('name==test;price>10'), true, 'validate: valid');

  -- rsql_validate: invalid
  RETURN NEXT is(pgv.rsql_validate('not a filter'), false, 'validate: invalid');

  -- rsql_validate: empty
  RETURN NEXT is(pgv.rsql_validate(''), true, 'validate: empty is valid');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_rsql() IS 'Tests pgv.rsql_to_where() and pgv.rsql_validate() — all operators, type-awareness, security';

CREATE OR REPLACE FUNCTION pgv_ut.test_rsql_fk()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
BEGIN
  -- Simple FK traversal
  v_result := pgv.rsql_to_where('charte.name==ocean', 'docs', 'document');
  RETURN NEXT is(v_result,
    'EXISTS (SELECT 1 FROM docs.charte WHERE id = document.charte_id AND name = ''ocean'')',
    'fk simple: charte.name==ocean');

  -- FK + local filter combined
  v_result := pgv.rsql_to_where('charte.font_heading=like=*Garamond*;status==draft', 'docs', 'document');
  RETURN NEXT is(v_result,
    'EXISTS (SELECT 1 FROM docs.charte WHERE id = document.charte_id AND font_heading LIKE ''%Garamond%'') AND status = ''draft''',
    'fk combined: charte.font + local status');

  -- Invalid relation → RAISE
  BEGIN
    v_result := pgv.rsql_to_where('nonexistent.name==test', 'docs', 'document');
    RETURN NEXT fail('invalid FK should raise');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT ok(SQLERRM LIKE '%not a column or FK relation%', 'invalid FK raises exception');
  END;

  -- Invalid column on target table → RAISE
  BEGIN
    v_result := pgv.rsql_to_where('charte.fakecol==test', 'docs', 'document');
    RETURN NEXT fail('invalid FK column should raise');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT ok(SQLERRM LIKE '%does not exist%', 'invalid FK target column raises');
  END;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_rsql_fk() IS 'Tests RSQL v3 — FK relation traversal via EXISTS subquery';

CREATE OR REPLACE FUNCTION pgv_ut.test_rsql_jsonb()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
BEGIN
  -- Simple jsonb key
  v_result := pgv.rsql_to_where('color_extra.ocean==#2E7D9B', 'docs', 'charte');
  RETURN NEXT is(v_result, 'color_extra->>''ocean'' = ''#2E7D9B''', 'jsonb simple: color_extra.ocean');

  -- LIKE on jsonb
  v_result := pgv.rsql_to_where('rules.layout=like=*marge*', 'docs', 'charte');
  RETURN NEXT is(v_result, 'rules->>''layout'' LIKE ''%marge%''', 'jsonb like: rules.layout');

  -- IS NULL on jsonb key
  v_result := pgv.rsql_to_where('color_extra.ocean=isnull=true', 'docs', 'charte');
  RETURN NEXT is(v_result, 'color_extra->>''ocean'' IS NULL', 'jsonb isnull');

  -- Nested path with array index
  v_result := pgv.rsql_to_where('voice_examples.0.good==test', 'docs', 'charte');
  RETURN NEXT is(v_result, 'voice_examples->0->>''good'' = ''test''', 'jsonb nested: array index + key');

  -- Non-jsonb column with no dot = normal column (regression)
  v_result := pgv.rsql_to_where('name==ocean', 'docs', 'charte');
  RETURN NEXT is(v_result, 'name = ''ocean''', 'non-jsonb stays simple');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_rsql_jsonb() IS 'Tests RSQL v2 — jsonb dot notation traversal';

CREATE OR REPLACE FUNCTION pgv_ut.test_schema_catalog()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
  v_item jsonb;
BEGIN
  v_result := pgv.schema_catalog();

  RETURN NEXT ok(jsonb_typeof(v_result) = 'array', 'returns jsonb array');
  RETURN NEXT ok(jsonb_array_length(v_result) > 0, 'at least one schema');

  -- workbench should be present
  SELECT item INTO v_item FROM jsonb_array_elements(v_result) AS item
  WHERE item->>'schema' = 'workbench';
  RETURN NEXT ok(v_item IS NOT NULL, 'workbench schema present');
  RETURN NEXT ok((v_item->>'tables')::int > 0, 'workbench has tables');
  RETURN NEXT ok((v_item->>'functions')::int > 0, 'workbench has functions');

  -- pgv should NOT be present (framework, not app)
  -- Actually pgv IS an app schema — check _ut/_qa excluded
  SELECT item INTO v_item FROM jsonb_array_elements(v_result) AS item
  WHERE item->>'schema' = 'pgv_ut';
  RETURN NEXT ok(v_item IS NULL, 'pgv_ut excluded');

  SELECT item INTO v_item FROM jsonb_array_elements(v_result) AS item
  WHERE item->>'schema' = 'pgv_qa';
  RETURN NEXT ok(v_item IS NULL, 'pgv_qa excluded');

  SELECT item INTO v_item FROM jsonb_array_elements(v_result) AS item
  WHERE item->>'schema' = 'information_schema';
  RETURN NEXT ok(v_item IS NULL, 'information_schema excluded');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_schema_catalog() IS 'Tests pgv.schema_catalog() — returns jsonb array of application schemas';

CREATE OR REPLACE FUNCTION pgv_ut.test_schema_comments()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
BEGIN
  v_result := pgv.schema_comments('workbench');

  RETURN NEXT ok(v_result IS NOT NULL, 'returns text');
  RETURN NEXT ok(v_result LIKE 'SCHEMA workbench%', 'starts with SCHEMA header');
  RETURN NEXT ok(v_result LIKE '%## agent_message%', 'contains agent_message table section');
  RETURN NEXT ok(v_result LIKE '%## tenant%', 'contains tenant table section');
  RETURN NEXT ok(v_result LIKE '%msg_type:%', 'contains column msg_type');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_schema_comments() IS 'Tests pgv.schema_comments() — text coverage of COMMENT ON';

CREATE OR REPLACE FUNCTION pgv_ut.test_schema_discover()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
  v_table jsonb;
  v_col jsonb;
BEGIN
  v_result := pgv.schema_discover('workbench');

  RETURN NEXT ok(jsonb_typeof(v_result) = 'array', 'returns jsonb array');
  RETURN NEXT ok(jsonb_array_length(v_result) >= 5, 'workbench has >= 5 tables');

  -- Find agent_message table
  SELECT item INTO v_table FROM jsonb_array_elements(v_result) AS item
  WHERE item->>'table' = 'agent_message';
  RETURN NEXT ok(v_table IS NOT NULL, 'agent_message table found');

  -- Columns
  RETURN NEXT ok(jsonb_array_length(v_table->'columns') > 5, 'agent_message has > 5 columns');

  -- Check a specific column
  SELECT col INTO v_col FROM jsonb_array_elements(v_table->'columns') AS col
  WHERE col->>'name' = 'msg_type';
  RETURN NEXT ok(v_col IS NOT NULL, 'msg_type column found');
  RETURN NEXT is(v_col->>'type', 'text', 'msg_type is text type');
  RETURN NEXT is((v_col->>'nullable')::bool, false, 'msg_type is NOT NULL');

  -- FK
  RETURN NEXT ok(jsonb_typeof(v_table->'foreign_keys') = 'array', 'foreign_keys is array');

  -- Empty schema
  v_result := pgv.schema_discover('nonexistent_schema_xyz');
  RETURN NEXT is(v_result, '[]'::jsonb, 'nonexistent schema returns empty array');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_schema_discover() IS 'Tests pgv.schema_discover() — returns tables with columns, FK, comments';

CREATE OR REPLACE FUNCTION pgv_ut.test_schema_inspect()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v text;
BEGIN
  -- Ensure api.expose=mcp flags are set (may be reset by docs agent redeploys)
  ALTER FUNCTION docs.charter_create(docs.charter) SET api.expose = 'mcp';
  ALTER FUNCTION docs.charter_read(text) SET api.expose = 'mcp';
  ALTER FUNCTION docs.charter_list() SET api.expose = 'mcp';
  ALTER FUNCTION docs.charter_delete(text) SET api.expose = 'mcp';
  ALTER FUNCTION docs.charter_tokens_to_css(text) SET api.expose = 'mcp';
  ALTER FUNCTION docs.charter_check(text, text) SET api.expose = 'mcp';
  ALTER FUNCTION docs.document_duplicate(text, text) SET api.expose = 'mcp';
  ALTER FUNCTION docs.document_print_css(text) SET api.expose = 'mcp';

  -- charter: full inspection
  v := pgv.schema_inspect('docs', 'charter');
  RETURN NEXT ok(v LIKE '## charter%', 'charter: header');
  RETURN NEXT ok(v LIKE '%attributes:%', 'charter: has attributes section');
  RETURN NEXT ok(v LIKE '%id%text%PK%', 'charter: id is PK');
  RETURN NEXT ok(v LIKE '%color_extra%jsonb%', 'charter: jsonb column present');
  RETURN NEXT ok(v LIKE '%voice_personality%text[]%', 'charter: array type formatted as text[]');

  -- CRUD
  RETURN NEXT ok(v LIKE '%crud:%', 'charter: has crud section');
  RETURN NEXT ok(v LIKE '%charter_create%', 'charter: create function listed');
  RETURN NEXT ok(v LIKE '%charter_read%', 'charter: read function listed');
  RETURN NEXT ok(v LIKE '%charter_list%', 'charter: list function listed');
  RETURN NEXT ok(v LIKE '%charter_delete%', 'charter: delete function listed');

  -- Methods
  RETURN NEXT ok(v LIKE '%methods:%', 'charter: has methods section');
  RETURN NEXT ok(v LIKE '%charter_tokens_to_css%', 'charter: tokens_to_css method');
  RETURN NEXT ok(v LIKE '%charter_check%', 'charter: check method');

  -- Relations
  RETURN NEXT ok(v LIKE '%relations:%', 'charter: has relations section');
  RETURN NEXT ok(v LIKE '%document -> charter_id FK%', 'charter: document FK relation');
  RETURN NEXT ok(v LIKE '%charter_revision -> charter_id FK%', 'charter: charter_revision FK relation');

  -- document: FK + methods
  v := pgv.schema_inspect('docs', 'document');
  RETURN NEXT ok(v LIKE '%charter_id%FK%', 'document: charter_id is FK');
  RETURN NEXT ok(v LIKE '%document_duplicate%', 'document: duplicate method');
  RETURN NEXT ok(v LIKE '%document_print_css%', 'document: print_css method');

  -- Missing entity
  v := pgv.schema_inspect('docs', 'nonexistent');
  RETURN NEXT ok(v LIKE '%not found%', 'missing entity: error message');


END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_schema_inspect() IS 'Tests pgv.schema_inspect() — LMNAV entity discovery with api.expose=mcp filtering';

CREATE OR REPLACE FUNCTION pgv_ut.test_schema_table()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
  v_check jsonb;
BEGIN
  v_result := pgv.schema_table('workbench', 'agent_message');

  RETURN NEXT is(v_result->>'schema', 'workbench', 'schema is workbench');
  RETURN NEXT is(v_result->>'table', 'agent_message', 'table is agent_message');
  RETURN NEXT ok(jsonb_array_length(v_result->'columns') > 5, 'has columns');

  -- CHECK constraints (msg_type, priority, status)
  RETURN NEXT ok(jsonb_array_length(v_result->'check_constraints') > 0, 'has check constraints');
  SELECT item INTO v_check FROM jsonb_array_elements(v_result->'check_constraints') AS item
  WHERE item->>'definition' LIKE '%msg_type%';
  RETURN NEXT ok(v_check IS NOT NULL, 'msg_type check constraint found');
  RETURN NEXT ok(v_check->>'definition' LIKE '%task%', 'msg_type check includes task');

  -- Indexes
  RETURN NEXT ok(jsonb_array_length(v_result->'indexes') >= 0, 'indexes is array');

  -- RLS on tenant table
  v_result := pgv.schema_table('workbench', 'tenant');
  RETURN NEXT is((v_result->'rls'->>'enabled')::bool, true, 'RLS is enabled on tenant');
  RETURN NEXT ok(jsonb_array_length(v_result->'rls'->'policies') > 0, 'tenant has RLS policies');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_schema_table() IS 'Tests pgv.schema_table() — detailed table structure with CHECK, FK, indexes, RLS';

CREATE OR REPLACE FUNCTION pgv_ut.test_search()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_item text;
  v_html text;
BEGIN
  -- search_item renders correctly
  v_item := pgv.search_item(ROW('/test?id=1', '📄', 'document', 'Mon doc', 'Detail ici', 0.9)::pgv.search_result);
  RETURN NEXT ok(v_item LIKE '%pgv-search-item%', 'search_item has pgv-search-item class');
  RETURN NEXT ok(v_item LIKE '%data-href="/test?id=1"%', 'search_item has data-href');
  RETURN NEXT ok(v_item LIKE '%pgv-search-icon%', 'search_item has icon');
  RETURN NEXT ok(v_item LIKE '%<strong>Mon doc</strong>%', 'search_item has label');
  RETURN NEXT ok(v_item LIKE '%pgv-badge%', 'search_item has kind badge');
  RETURN NEXT ok(v_item LIKE '%<small>Detail ici</small>%', 'search_item has detail');

  -- search_item escapes label
  v_item := pgv.search_item(ROW('/x', NULL, NULL, '<script>xss</script>', NULL, 0.5)::pgv.search_result);
  RETURN NEXT ok(v_item NOT LIKE '%<script>%', 'search_item escapes label');

  -- search_item without optional fields
  v_item := pgv.search_item(ROW('/x', NULL, NULL, 'Simple', NULL, 0.5)::pgv.search_result);
  RETURN NEXT ok(v_item NOT LIKE '%pgv-search-icon%', 'search_item without icon omits icon span');
  RETURN NEXT ok(v_item NOT LIKE '%pgv-badge%', 'search_item without kind omits badge');
  RETURN NEXT ok(v_item NOT LIKE '%<small>%', 'search_item without detail omits small');

  -- search dispatcher finds pgv_qa.search()
  v_html := pgv.search('doc', 'pgv_qa');
  RETURN NEXT ok(v_html LIKE '%pgv-search-results%', 'search returns results list');
  RETURN NEXT ok(v_html LIKE '%Premier document%', 'search finds matching item');

  -- search with no matches
  v_html := pgv.search('zzzznotfound', 'pgv_qa');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'search no match returns empty state');

  -- search on schema without search() function
  v_html := pgv.search('test', 'pgv_ut');
  RETURN NEXT ok(v_html LIKE '%non disponible%', 'search on schema without provider returns message');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_search() IS 'Tests for pgv.search_item() and pgv.search() dispatcher';

CREATE OR REPLACE FUNCTION pgv_ut.test_select_search()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- Basic rendering
  v_html := pgv.select_search('p_article', 'Article', 'catalog.article_options', 'Rechercher...');
  RETURN NEXT ok(v_html LIKE '%data-ss-rpc="catalog.article_options"%', 'data-ss-rpc attribute present');
  RETURN NEXT ok(v_html LIKE '%class="pgv-ss"%', 'pgv-ss container class');
  RETURN NEXT ok(v_html LIKE '%class="pgv-ss-input"%', 'pgv-ss-input class on text input');
  RETURN NEXT ok(v_html LIKE '%name="p_article"%', 'hidden input has correct name');
  RETURN NEXT ok(v_html LIKE '%placeholder="Rechercher..."%', 'placeholder set');
  RETURN NEXT ok(v_html LIKE '%autocomplete="off"%', 'autocomplete off');

  -- Pre-filled value
  v_html := pgv.select_search('p_item', 'Item', 'ns.fn', '', '42', 'Widget XL');
  RETURN NEXT ok(v_html LIKE '%value="42"%', 'hidden input pre-filled with value');
  RETURN NEXT ok(v_html LIKE '%value="Widget XL"%', 'text input pre-filled with display');

  -- XSS escaping
  v_html := pgv.select_search('x', '<script>', 'a.b">', '<">');
  RETURN NEXT ok(v_html NOT LIKE '%<script>%', 'label escaped');
  RETURN NEXT ok(v_html NOT LIKE '%a.b">%', 'rpc escaped');

  -- No value / no display
  v_html := pgv.select_search('p_id', 'Choose', 'x.y');
  RETURN NEXT ok(v_html NOT LIKE '%value="%', 'no value attributes when NULL');
  RETURN NEXT ok(v_html LIKE '%placeholder=""%', 'empty placeholder default');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_select_search() IS 'Unit tests for pgv.select_search() primitive';

CREATE OR REPLACE FUNCTION pgv_ut.test_slugify()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Basic
  RETURN NEXT is(pgv.slugify('Hello World'), 'hello-world', 'basic: lowercase + space');

  -- Accents
  RETURN NEXT is(pgv.slugify('Gîte en Provence'), 'gite-en-provence', 'accents: î→i');
  RETURN NEXT is(pgv.slugify('DÉJÀ VU café crème'), 'deja-vu-cafe-creme', 'accents: é è ê');
  RETURN NEXT is(pgv.slugify('Cormorant Garamond'), 'cormorant-garamond', 'no accents: passthrough');

  -- Multipart
  RETURN NEXT is(pgv.slugify('restaurant', 'Menu Été'), 'restaurant-menu-ete', 'multipart: 2 parts');
  RETURN NEXT is(pgv.slugify('devis', 'Maison', 'Martin'), 'devis-maison-martin', 'multipart: 3 parts');

  -- Cleanup
  RETURN NEXT is(pgv.slugify('  Espaces  multiples  '), 'espaces-multiples', 'cleanup: multiple spaces');
  RETURN NEXT is(pgv.slugify('a--b--c'), 'a-b-c', 'cleanup: multiple dashes');

  -- Special chars
  RETURN NEXT is(pgv.slugify('L''Olivier & Fils'), 'l-olivier-fils', 'special: apostrophe + &');

  -- NULL handling
  RETURN NEXT is(pgv.slugify(NULL, 'test'), 'test', 'null: first part null');
  RETURN NEXT is(pgv.slugify('a', NULL, 'b'), 'a-b', 'null: middle part null');

  -- Empty
  RETURN NEXT is(pgv.slugify(''), '', 'empty: returns empty');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_slugify() IS 'Tests pgv.slugify() — slug generation with accents, multipart, cleanup';

CREATE OR REPLACE FUNCTION pgv_ut.test_stat()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := pgv.stat('Label', '42', 'detail');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'stat has pgv-stat class');
  RETURN NEXT ok(v_html LIKE '%pgv-stat-value%', 'stat has pgv-stat-value class');
  RETURN NEXT ok(v_html NOT LIKE '%style=%', 'stat has no inline style');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_stat() IS 'Unit tests for pgv.stat: CSS classes, no inline style';

CREATE OR REPLACE FUNCTION pgv_ut.test_table()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v text;
  v_config jsonb;
BEGIN
  -- Minimal config
  v_config := '{"rpc":"data_test","schema":"test","cols":[{"key":"id","label":"#"}]}'::jsonb;
  v := pgv.table(v_config);
  RETURN NEXT ok(v LIKE '%x-data="pgvTable"%', 'has Alpine pgvTable directive');
  RETURN NEXT ok(v LIKE '%data-config=%', 'has data-config attribute');
  RETURN NEXT ok(v LIKE '%data_test%', 'config contains rpc name');
  RETURN NEXT ok(v LIKE '%<div %', 'wrapper is div');

  -- Config with filters
  v_config := jsonb_build_object(
    'rpc', 'data_items',
    'schema', 'myapp',
    'page_size', 15,
    'filters', jsonb_build_array(
      jsonb_build_object('name', 'p_status', 'type', 'select', 'label', 'Statut',
        'options', jsonb_build_array(jsonb_build_array('', 'Tous'), jsonb_build_array('active', 'Actif'))),
      jsonb_build_object('name', 'q', 'type', 'search', 'label', 'Recherche')),
    'cols', jsonb_build_array(
      jsonb_build_object('key', 'id', 'label', '#'),
      jsonb_build_object('key', 'name', 'label', 'Nom'),
      jsonb_build_object('key', 'status', 'label', 'Statut', 'class', 'pgv-col-badge'))
  );
  v := pgv.table(v_config);
  RETURN NEXT ok(v LIKE '%data_items%', 'config contains rpc');
  RETURN NEXT ok(v LIKE '%myapp%', 'config contains schema');
  RETURN NEXT ok(v LIKE '%page_size%', 'config contains page_size');
  RETURN NEXT ok(v LIKE '%p_status%', 'config contains filter name');
  RETURN NEXT ok(v LIKE '%pgv-col-badge%', 'config contains column class');
  RETURN NEXT ok(v LIKE '%Recherche%', 'config contains search label');

  -- HTML escaping
  v_config := '{"rpc":"test","schema":"s","cols":[{"key":"x","label":"A&B"}]}'::jsonb;
  v := pgv.table(v_config);
  RETURN NEXT ok(v LIKE '%A&amp;B%', 'label is HTML-escaped in attribute');

  -- No inline styles
  RETURN NEXT ok(v NOT LIKE '%style=%', 'no inline styles');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_table() IS 'Unit tests for pgv.table() declarative table primitive';

