$function$;
COMMENT ON FUNCTION pgv_ut.test_tabs() IS 'Unit tests for pgv.tabs: nav class, Alpine x-data, labels, content';

CREATE OR REPLACE FUNCTION pgv_ut.test_timeline()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_items jsonb := '[
    {"date":"2026-03-10","label":"Devis créé","detail":"Montant: 1500€ HT","badge":"info"},
    {"date":"2026-03-11","label":"Devis envoyé","badge":"success"},
    {"date":"2026-03-12","label":"Paiement reçu","detail":"Virement bancaire","badge":"primary"}
  ]';
BEGIN
  v_html := pgv.timeline(v_items);

  -- Container
  RETURN NEXT ok(v_html LIKE '%class="pgv-tl"%', 'container class pgv-tl');

  -- Items rendered
  RETURN NEXT ok(v_html LIKE '%pgv-tl-item%', 'timeline items present');
  RETURN NEXT ok(v_html LIKE '%pgv-tl-dot%', 'dot elements present');

  -- Dates
  RETURN NEXT ok(v_html LIKE '%pgv-tl-date%', 'date rendered');
  RETURN NEXT ok(v_html LIKE '%2026-03-10%', 'first date value');

  -- Labels
  RETURN NEXT ok(v_html LIKE '%pgv-tl-label%', 'label rendered');
  RETURN NEXT ok(v_html LIKE '%Devis créé%', 'first label value');

  -- Detail
  RETURN NEXT ok(v_html LIKE '%pgv-tl-detail%', 'detail rendered');
  RETURN NEXT ok(v_html LIKE '%1500%', 'detail content');

  -- Badge colors on dots
  RETURN NEXT ok(v_html LIKE '%pgv-tl-dot-info%', 'info dot color');
  RETURN NEXT ok(v_html LIKE '%pgv-tl-dot-success%', 'success dot color');
  RETURN NEXT ok(v_html LIKE '%pgv-tl-dot-primary%', 'primary dot color');

  -- No badge → plain dot
  v_html := pgv.timeline('[{"label":"Simple event"}]');
  RETURN NEXT ok(v_html LIKE '%class="pgv-tl-dot"%', 'plain dot without badge');
  RETURN NEXT ok(v_html NOT LIKE '%pgv-tl-date%', 'no date when omitted');
  RETURN NEXT ok(v_html NOT LIKE '%pgv-tl-detail%', 'no detail when omitted');

  -- XSS
  v_html := pgv.timeline('[{"label":"<script>alert(1)</script>"}]');
  RETURN NEXT ok(v_html NOT LIKE '%<script>%', 'labels escaped');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_timeline() IS 'Unit tests for pgv.timeline() vertical timeline primitive';

CREATE OR REPLACE FUNCTION pgv_ut.test_toast()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE v text;
BEGIN
  v := pgv.toast('Saved!');
  RETURN NEXT ok(v ~ '<template data-toast="success">', 'default level is success');
  RETURN NEXT ok(v ~ '>Saved!</template>', 'message content');

  v := pgv.toast('Erreur!', 'error');
  RETURN NEXT ok(v ~ 'data-toast="error"', 'error level');
  RETURN NEXT ok(v ~ '>Erreur!</template>', 'error message');

  -- XSS safety
  v := pgv.toast('<script>alert(1)</script>');
  RETURN NEXT ok(v !~ '<script>', 'message is escaped');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_toast() IS 'Tests for pgv.toast() POST response primitive';

CREATE OR REPLACE FUNCTION pgv_ut.test_toggle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := pgv.toggle('dark', 'Dark mode');
  RETURN NEXT ok(v_html LIKE '%role="switch"%', 'toggle has role=switch');
  RETURN NEXT ok(v_html LIKE '%name="dark"%', 'toggle has name');
  RETURN NEXT ok(v_html NOT LIKE '%checked%', 'toggle unchecked by default');

  v_html := pgv.toggle('auto', 'Auto', true);
  RETURN NEXT ok(v_html LIKE '%checked%', 'toggle checked when p_checked=true');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_toggle() IS 'Unit tests for pgv.toggle: role=switch, name, checked state';

CREATE OR REPLACE FUNCTION pgv_ut.test_tree()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- Leaf node
  v_html := pgv.tree('[{"label": "Feuille"}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<ul class="pgv-tree">%', 'tree has pgv-tree class');
  RETURN NEXT ok(v_html LIKE '%<li>Feuille</li>%', 'leaf node renders text');

  -- Link node
  v_html := pgv.tree('[{"label": "Lien", "href": "/page"}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<a href="/page">Lien</a>%', 'link node has href');

  -- Branch node (closed by default)
  v_html := pgv.tree('[{"label": "Parent", "children": [{"label": "Enfant"}]}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<details>%', 'branch has details tag');
  RETURN NEXT ok(v_html LIKE '%<summary>Parent</summary>%', 'branch has summary');
  RETURN NEXT ok(v_html NOT LIKE '%<details open%', 'branch closed by default');

  -- Branch node (open)
  v_html := pgv.tree('[{"label": "Ouvert", "open": true, "children": [{"label": "Visible"}]}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<details open%', 'open branch has details open');

  -- Global open
  v_html := pgv.tree('[{"label": "A", "children": [{"label": "B"}]}]'::jsonb, true);
  RETURN NEXT ok(v_html LIKE '%<details open%', 'p_open=true opens all branches');

  -- Nested depth (no pgv-tree class on inner ul)
  v_html := pgv.tree('[{"label": "L1", "children": [{"label": "L2", "children": [{"label": "L3"}]}]}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<ul class="pgv-tree"><li><details><summary>L1</summary><ul><li>%',
    'inner ul has no pgv-tree class');

  -- XSS escape
  v_html := pgv.tree('[{"label": "<script>alert(1)</script>"}]'::jsonb);
  RETURN NEXT ok(v_html NOT LIKE '%<script>%', 'label is HTML-escaped');

  -- Icon (raw HTML, not escaped)
  v_html := pgv.tree('[{"label": "Fichier", "icon": "📄"}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<span class="pgv-tree-icon">%', 'icon has pgv-tree-icon class');
  RETURN NEXT ok(v_html LIKE '%pgv-tree-icon">📄</span> Fichier%', 'icon before label');

  v_html := pgv.tree('[{"label": "Pièce", "icon": "<span class=\"cad-swatch\" data-color=\"#c8956c\"></span>"}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<span class="cad-swatch"%', 'icon accepts raw HTML');

  -- Badge
  v_html := pgv.tree('[{"label": "Dossier", "badge": "3"}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%pgv-badge%', 'badge renders pgv-badge');
  RETURN NEXT ok(v_html LIKE '%Dossier%pgv-badge%', 'badge after label');

  -- Action (object -> pgv.action)
  v_html := pgv.tree('[{"label": "Item", "action": {"rpc": "delete_item", "label": "Suppr", "params": {"id": 1}, "confirm": "Sûr?"}}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%data-rpc="delete_item"%', 'action object has data-rpc');
  RETURN NEXT ok(v_html LIKE '%data-confirm="Sûr?"%', 'action object has data-confirm');
  RETURN NEXT ok(v_html LIKE '%data-params%', 'action object has data-params');

  -- Action (string -> raw HTML)
  v_html := pgv.tree('[{"label": "Vis", "action": "<button class=\"cad-eye\" @click.stop=\"toggle(7)\">◉</button>"}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<button class="cad-eye"%', 'action string renders raw HTML');
  RETURN NEXT ok(v_html LIKE '%@click.stop="toggle(7)"%', 'action string preserves Alpine attrs');

  -- Attrs on li
  v_html := pgv.tree('[{"label": "Pièce", "attrs": "data-id=\"42\" class=\"selected\""}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<li data-id="42" class="selected">%', 'attrs on li');

  -- Root attrs
  v_html := pgv.tree('[{"label": "A"}]'::jsonb, false, 0, 'id="my-tree" data-sync="viewer"');
  RETURN NEXT ok(v_html LIKE '%<ul class="pgv-tree" id="my-tree" data-sync="viewer">%', 'root_attrs on ul');

  -- Icon on branch summary
  v_html := pgv.tree('[{"label": "Groupe", "icon": "📁", "children": [{"label": "Sub"}]}]'::jsonb);
  RETURN NEXT ok(v_html LIKE '%<summary><span class="pgv-tree-icon">📁</span> Groupe</summary>%', 'icon in branch summary');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_tree() IS 'Unit tests for pgv.tree: leaf, link, branch, open, depth, XSS, icon (raw HTML), badge, action (object + string), attrs, root_attrs';

CREATE OR REPLACE FUNCTION pgv_ut.test_ui_form_for()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v jsonb;
  f jsonb;
BEGIN
  v := pgv.ui_form_for('docs', 'charter');

  -- Structure
  RETURN NEXT is(v->>'type', 'form', 'type is form');
  RETURN NEXT is(v->>'uri', 'docs://charter', 'uri is docs://charter');
  RETURN NEXT is(v->>'verb', 'set', 'default verb is set');
  RETURN NEXT ok(jsonb_array_length(v->'fields') > 5, 'has multiple fields');

  -- Text column → text field
  SELECT item INTO f FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'name';
  RETURN NEXT is(f->>'fieldType', 'text', 'text column → text field');
  RETURN NEXT is((f->>'required')::bool, true, 'NOT NULL → required');

  -- Excluded columns
  RETURN NEXT ok(
    NOT EXISTS (SELECT 1 FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'id'),
    'id excluded'
  );
  RETURN NEXT ok(
    NOT EXISTS (SELECT 1 FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'tenant_id'),
    'tenant_id excluded'
  );

  -- COMMENT ON → label
  SELECT item INTO f FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'color_bg';
  RETURN NEXT ok(f->>'label' != 'color bg', 'COMMENT ON used as label (not column name)');

  -- jsonb → textarea
  SELECT item INTO f FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'rules';
  RETURN NEXT is(f->>'fieldType', 'textarea', 'jsonb → textarea');

  -- Document: FK → select, numeric → number
  v := pgv.ui_form_for('docs', 'document');
  SELECT item INTO f FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'charter_id';
  RETURN NEXT is(f->>'fieldType', 'select', 'FK → select');
  RETURN NEXT ok(f->'options'->>'source' LIKE '%://charter', 'FK select has source');

  SELECT item INTO f FROM jsonb_array_elements(v->'fields') item WHERE item->>'key' = 'width';
  RETURN NEXT is(f->>'fieldType', 'number', 'numeric → number');

  -- Verb override
  v := pgv.ui_form_for('docs', 'charter', 'patch');
  RETURN NEXT is(v->>'verb', 'patch', 'verb override works');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_ui_form_for() IS 'Tests pgv.ui_form_for() — auto-generated SDUI form from pg introspection';

CREATE OR REPLACE FUNCTION pgv_ut.test_ui_card()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v jsonb;
  h jsonb;
BEGIN
  -- ui_card_header
  h := pgv.ui_card_header('◎', 'Test', pgv.ui_badge('VIP', 'success'));
  RETURN NEXT is(h->>'icon', '◎', 'header: icon');
  RETURN NEXT is(h->>'title', 'Test', 'header: title');
  RETURN NEXT ok(jsonb_array_length(h->'badges') = 1, 'header: 1 badge');

  -- header without badges
  h := pgv.ui_card_header('✉', 'No badges');
  RETURN NEXT ok(h->'badges' IS NULL, 'header: no badges key when empty');

  -- ui_stat
  v := pgv.ui_stat('42', 'Count');
  RETURN NEXT is(v->>'type', 'stat', 'stat: type');
  RETURN NEXT is(v->>'value', '42', 'stat: value');
  RETURN NEXT is(v->>'label', 'Count', 'stat: label');
  RETURN NEXT ok(v->'variant' IS NULL, 'stat: no variant by default');

  v := pgv.ui_stat('3', 'Pending', 'warn');
  RETURN NEXT is(v->>'variant', 'warn', 'stat: variant set');

  -- ui_card compact
  v := pgv.ui_card('crm://client/1', 'compact', pgv.ui_card_header('◎', 'Dupont'));
  RETURN NEXT is(v->>'type', 'card', 'compact: type');
  RETURN NEXT is(v->>'level', 'compact', 'compact: level');
  RETURN NEXT is(v->>'entity_uri', 'crm://client/1', 'compact: entity_uri');
  RETURN NEXT ok(v->'body' IS NULL, 'compact: no body');
  RETURN NEXT ok(v->'actions' IS NULL, 'compact: no actions');

  -- ui_card standard
  v := pgv.ui_card(
    'docs://charte/ocean', 'standard',
    pgv.ui_card_header('🎨', 'Ocean'),
    jsonb_build_array(pgv.ui_stat('6', 'Couleurs')),
    jsonb_build_array(pgv.ui_card('docs://document/1', 'compact', pgv.ui_card_header('📄', 'Facture')))
  );
  RETURN NEXT is(v->>'level', 'standard', 'standard: level');
  RETURN NEXT ok(jsonb_array_length(v->'body') = 1, 'standard: has body');
  RETURN NEXT ok(jsonb_array_length(v->'related') = 1, 'standard: has related');
  RETURN NEXT is(v->'related'->0->>'level', 'compact', 'standard: related is compact card');
  RETURN NEXT ok(v->'actions' IS NULL, 'standard: no actions');

  -- ui_card expanded
  v := pgv.ui_card(
    'docs://charte/ocean', 'expanded',
    pgv.ui_card_header('🎨', 'Ocean'),
    jsonb_build_array(pgv.ui_stat('6', 'Couleurs')),
    NULL,
    jsonb_build_array(pgv.ui_action('Supprimer', 'delete', 'docs://charte/ocean', 'danger', 'Confirmer ?'))
  );
  RETURN NEXT is(v->>'level', 'expanded', 'expanded: level');
  RETURN NEXT ok(jsonb_array_length(v->'actions') = 1, 'expanded: has actions');
  RETURN NEXT is(v->'actions'->0->>'verb', 'delete', 'expanded: action verb');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_ui_card() IS 'Tests pgv.ui_card, ui_card_header, ui_stat — SDUI entity cards at 3 levels';

CREATE OR REPLACE FUNCTION pgv_ut.test_ui_tier1()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v jsonb;
BEGIN
  -- ui_timeline
  v := pgv.ui_timeline('[{"date":"2026-03-12","label":"Created","variant":"info"},{"date":"2026-03-13","label":"Sent"}]'::jsonb);
  RETURN NEXT is(v->>'type', 'timeline', 'timeline: type');
  RETURN NEXT is(jsonb_array_length(v->'events'), 2, 'timeline: 2 events');
  RETURN NEXT is(v->'events'->0->>'label', 'Created', 'timeline: first event label');
  RETURN NEXT is(v->'events'->0->>'variant', 'info', 'timeline: first event variant');

  -- ui_currency
  v := pgv.ui_currency(5200.50);
  RETURN NEXT is(v->>'type', 'currency', 'currency: type');
  RETURN NEXT ok((v->>'amount')::numeric = 5200.50, 'currency: amount');
  RETURN NEXT is(v->>'currency', 'EUR', 'currency: default EUR');

  v := pgv.ui_currency(-100, 'USD');
  RETURN NEXT is(v->>'currency', 'USD', 'currency: custom currency');
  RETURN NEXT ok((v->>'amount')::numeric = -100, 'currency: negative');

  -- ui_workflow
  v := pgv.ui_workflow(ARRAY['draft','sent','accepted'], 'sent');
  RETURN NEXT is(v->>'type', 'workflow', 'workflow: type');
  RETURN NEXT is(v->>'current', 'sent', 'workflow: current state');
  RETURN NEXT is(jsonb_array_length(v->'states'), 3, 'workflow: 3 states');
  RETURN NEXT is(v->'states'->>0, 'draft', 'workflow: first state');

  -- ui_line_items
  v := pgv.ui_line_items('lines', '[{"key":"desc","label":"Description"},{"key":"qty","label":"Qty"}]'::jsonb);
  RETURN NEXT is(v->>'type', 'line_items', 'line_items: type');
  RETURN NEXT is(v->>'source', 'lines', 'line_items: source');
  RETURN NEXT is(jsonb_array_length(v->'columns'), 2, 'line_items: 2 columns');
  RETURN NEXT ok(v->'totals' IS NULL, 'line_items: no totals by default');

  v := pgv.ui_line_items('lines', '[]'::jsonb, '{"ht":1017.50,"tva":124.50,"ttc":1142.00}'::jsonb);
  RETURN NEXT ok((v->'totals'->>'ttc')::numeric = 1142.00, 'line_items: totals ttc');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_ui_tier1() IS 'Tests Tier 1 SDUI primitives: ui_timeline, ui_currency, ui_workflow, ui_line_items';

CREATE OR REPLACE FUNCTION pgv_ut.test_route_crud()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- get :// → catalog
  v := pgv.route_crud('get', '://');
  RETURN NEXT ok(jsonb_typeof(v->'data') = 'array', 'catalog: returns array');
  RETURN NEXT is(v->>'uri', '://', 'catalog: uri preserved');

  -- get schema:// → discover
  v := pgv.route_crud('get', 'docs://');
  RETURN NEXT ok(jsonb_typeof(v->'data') = 'array', 'discover: returns array');

  -- get schema://entity#schema → schema_table
  v := pgv.route_crud('get', 'docs://charter#schema');
  RETURN NEXT is(v->'data'->>'table', 'charter', 'schema: returns table detail');

  -- get schema://entity → list
  v := pgv.route_crud('get', 'docs://charter');
  RETURN NEXT ok(v ? 'data', 'list: has data key');
  RETURN NEXT is(v->>'uri', 'docs://charter', 'list: uri preserved');

  -- get schema://entity/{id} → read (fallback to _load)
  v := pgv.route_crud('get', 'docs://charter/nonexistent_id');
  RETURN NEXT ok(v ? 'data', 'read: has data key');

  -- HATEOAS: actions extracted from _read() response (module is responsible)
  v := pgv.route_crud('get', 'docs://charter/test');
  RETURN NEXT ok(jsonb_typeof(v->'actions') = 'array', 'hateoas: actions is array');
  RETURN NEXT ok(v ? 'actions', 'hateoas: actions key always present');

  -- Error: nonexistent schema
  v := pgv.route_crud('get', 'nonexistent://test');
  RETURN NEXT is(v->>'error', 'not_found', 'error: bad schema');

  -- Error: nonexistent entity
  v := pgv.route_crud('get', 'docs://fakentity');
  RETURN NEXT is(v->>'error', 'not_found', 'error: bad entity');

  -- Error: bad verb
  v := pgv.route_crud('badverb', 'docs://charter');
  RETURN NEXT is(v->>'error', 'bad_request', 'error: bad verb');

  -- Error: POST without method
  v := pgv.route_crud('post', 'docs://charter/test');
  RETURN NEXT is(v->>'error', 'bad_request', 'error: post without method');

  -- Slug-based read
  v := pgv.route_crud('get', 'docs://charter/my-slug-name');
  RETURN NEXT ok(v ? 'data', 'slug: read passes segment to _read');
  RETURN NEXT is(v->>'uri', 'docs://charter/my-slug-name', 'slug: uri preserved with slug');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route_crud() IS 'Tests pgv.route_crud() — CRUD router dispatch, HATEOAS with api.expose=mcp, errors';

CREATE OR REPLACE FUNCTION pgv_ut.test_workflow()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_steps jsonb := '[{"key":"draft","label":"Brouillon"},{"key":"sent","label":"Envoyé"},{"key":"paid","label":"Payé"}]';
BEGIN
  -- Current at middle
  v_html := pgv.workflow(v_steps, 'sent');
  RETURN NEXT ok(v_html LIKE '%class="pgv-wf"%', 'container class pgv-wf');
  RETURN NEXT ok(v_html LIKE '%pgv-wf-done%', 'past step has done class');
  RETURN NEXT ok(v_html LIKE '%pgv-wf-current%', 'current step highlighted');
  RETURN NEXT ok(v_html LIKE '%pgv-wf-future%', 'future step marked');
  RETURN NEXT ok(v_html LIKE '%pgv-wf-line-done%', 'done connector line');
  RETURN NEXT ok(v_html LIKE '%Brouillon%', 'label rendered');
  RETURN NEXT ok(v_html LIKE '%pgv-wf-dot%', 'dot elements present');

  -- Current at first
  v_html := pgv.workflow(v_steps, 'draft');
  RETURN NEXT ok(v_html NOT LIKE '%pgv-wf-done%', 'no done steps when current is first');
  RETURN NEXT ok(v_html LIKE '%pgv-wf-current%', 'first step is current');

  -- Current at last
  v_html := pgv.workflow(v_steps, 'paid');
  RETURN NEXT ok(v_html NOT LIKE '%pgv-wf-future%', 'no future steps when current is last');
  RETURN NEXT ok((SELECT count(*) FROM regexp_matches(v_html, 'pgv-wf-done', 'g')) = 2, 'two done steps before last');

  -- XSS
  v_html := pgv.workflow('[{"key":"a","label":"<script>alert(1)</script>"}]', 'a');
  RETURN NEXT ok(v_html NOT LIKE '%<script>%', 'labels escaped');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_workflow() IS 'Unit tests for pgv.workflow() progress bar primitive';

